 /**
- * Allocate an integer-cent total across positive integer weights.
- * Stub — the coding agent implements this at eval time (task 002).
+ * Splits `total` across the given positive integer `weights` in proportion to
+ * each weight, returning one share per weight. Throws if `weights` is empty or
+ * contains a value that is not a positive number.
  */
 export function allocateProportional(total: number, weights: number[]): number[] {
-  throw new Error(`allocateProportional not implemented (total ${total}, ${weights.length} weights)`);
+  if (weights.length === 0) {
+    throw new Error("Cannot allocate with an empty weights array.");
+  }
+
+  let totalWeight = 0;
+  for (const weight of weights) {
+    if (!Number.isInteger(weight) || weight <= 0) {
+      throw new Error("Weights must be positive integers.");
+    }
+    totalWeight += weight;
+  }
+
+  const shares = weights.map(weight => {
+    return Math.floor((total * weight) / totalWeight);
+  });
+
+  const allocatedSum = shares.reduce((sum, share) => sum + share, 0);
+  const remainder = total - allocatedSum;
+
+  for (let i = 0; i < remainder; i++) {
+    shares[i]++;
+  }
+
+  return shares;
 }
